// Calculate 15 weeks of Sunday-start date ranges (matching BrightGauge)
const now = new Date();
const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

// Find this Sunday (start of current week)
const dayOfWeek = today.getDay(); // 0=Sun, 1=Mon...
const sunday = new Date(today);
sunday.setDate(today.getDate() - dayOfWeek);

const weeks = [];
for (let i = 14; i >= 0; i--) {
  const weekStart = new Date(sunday);
  weekStart.setDate(sunday.getDate() - (i * 7));
  const weekEnd = new Date(weekStart);
  weekEnd.setDate(weekStart.getDate() + 6);
  const endDate = weekEnd > today ? today : weekEnd;
  weeks.push({
    weekStart: weekStart.toISOString().split('T')[0],
    weekEnd: endDate.toISOString().split('T')[0],
    weekStartISO: weekStart.toISOString(),
    weekEndISO: new Date(endDate.getTime() + 86400000).toISOString()
  });
}

return [{ json: { weeks, nowISO: now.toISOString() } }];

// Calculate Metrics v3 - Mgmt Scorecard
// Fixes: open ticket filter, SLA breach detection, kill rate precision,
// sales won tracking via _info.lastUpdated, revenue from forecast

const dateRanges = $('Set Date Ranges').first().json;
const weeks = dateRanges.weeks;

// Combine all closed ticket pages
const closedItems = [
  ...$('Get Closed Tickets').all(),
  ...$('Get Closed Tickets P2').all(),
  ...$('Get Closed Tickets P3').all(),
  ...$('Get Closed Tickets P4').all(),
  ...$('Get Closed Tickets P5').all()
];

const openItems = $('Get Open Tickets').all();
const allTickets = [...openItems, ...closedItems];

const safeAll = (name) => { try { return $('' + name).all() || []; } catch (e) { return []; } };
const timeItems = [
  ...safeAll('Get Time Entries'), ...safeAll('Get Time Entries P2'),
  ...safeAll('Get Time Entries P3'), ...safeAll('Get Time Entries P4'),
  ...safeAll('Get Time Entries P5'), ...safeAll('Get Time Entries P6'),
  ...safeAll('Get Time Entries P7'), ...safeAll('Get Time Entries P8')
];

const openOpps = safeAll('Get Open Opportunities');
const openProjects = safeAll('Get Open Projects');

// --- Parked statuses for open ticket count (matches BG) ---
const PARKED_STATUSES = [
  'Scheduled', 'NCR Closed', 'Completed-NoResponse*',
  'Completed-Duplicate', 'SecInc Closed'
];

function toETDate(isoStr) {
  if (!isoStr) return null;
  const d = new Date(isoStr);
  d.setHours(d.getHours() - 5);
  return d.toISOString().split('T')[0];
}

function inWeek(dateStr, weekStart, weekEnd) {
  return dateStr >= weekStart && dateStr <= weekEnd;
}

function inRange(dateStr, rangeStart, rangeEnd) {
  return dateStr >= rangeStart && dateStr <= rangeEnd;
}

// Parse SLA status "Respond by" date strings
function isSlaBreached(slaStatus, asOfDate) {
  if (!slaStatus) return null; // no SLA tracking
  if (slaStatus === 'Resolved') return false;
  if (slaStatus === 'Waiting') return false;
  if (slaStatus.startsWith('Respond by') || slaStatus.startsWith('Resolve by') || slaStatus.startsWith('Plan by')) {
    // Parse date like "Respond by Mon 03/16 5:00 PM UTC-04"
    const match = slaStatus.match(/(\d{2})\/(\d{2})\s+(\d{1,2}):(\d{2})\s+(AM|PM)\s+UTC([+-]\d{2})/);
    if (match) {
      const month = parseInt(match[1]) - 1;
      const day = parseInt(match[2]);
      let hour = parseInt(match[3]);
      const min = parseInt(match[4]);
      const ampm = match[5];
      const tzOffset = parseInt(match[6]);

      if (ampm === 'PM' && hour < 12) hour += 12;
      if (ampm === 'AM' && hour === 12) hour = 0;

      // Figure out the year - assume current year or last year
      const now = new Date(asOfDate + 'T23:59:59Z');
      let year = now.getFullYear();
      let respondDate = new Date(year, month, day, hour - tzOffset, min);
      // If respond date is way in the future (>6 months), it's probably last year
      if (respondDate > new Date(now.getTime() + 180 * 86400000)) {
        respondDate = new Date(year - 1, month, day, hour - tzOffset, min);
      }

      return respondDate < now;
    }
    // Can't parse, assume not breached
    return false;
  }
  return false;
}

// Separate Won/Lost/Open opportunities
