    const t = item.json;
    const closedDate = toETDate(t.closedDate);
    if (closedDate && inRange(closedDate, slaRangeStart, we)) {
      if (t.slaStatus) {
        slaTotalCount++;
        const breached = isSlaBreached(t.slaStatus, we);
        if (!breached) slaMetCount++;
      }
    }
  }

  // Check open tickets created in 30-day window
