    killRate7, killRate14, slaPct,
    totalHours: Math.round(totalHours * 100) / 100,
    billableHours: Math.round(billableHours * 100) / 100,
    openCount,
    oppsClosed, oppsWon, wonRevenue, openOppsCount, openOppsRevenue,
    openProjectCount, budgetedHours, actualProjectHours
  });
