    }
  }

  // Open tickets - current week only, filtered
  let openCount = null;
  if (isCurrentWeek) {
    openCount = openItems.filter(i => {
      const statusName = i.json.status?.name || '';
      return !PARKED_STATUSES.includes(statusName);
    }).length;
  }

  // ---- SALES ----
  // Open opps - store for all weeks (current snapshot)
  const openOppsCount = trueOpenOpps.length;
  let openOppsRevenue = 0;
  for (const item of trueOpenOpps) {
    openOppsRevenue += parseFloat(item.json.totalSalesTax || 0);
  }
  openOppsRevenue = Math.round(openOppsRevenue * 100) / 100;

  // Won/Closed this week - use _info.lastUpdated as approximation
  let oppsClosed = 0, oppsWon = 0, wonRevenue = 0;

  // Won opps - check lastUpdated in this week
  for (const item of wonOpps) {
    const updated = toETDate(item.json._info?.lastUpdated);
    if (updated && inWeek(updated, ws, we)) {
      oppsWon++;
      wonRevenue += parseFloat(item.json.totalSalesTax || 0);
    }
  }

  // All closed (won + lost + no decision) this week
  for (const item of lostOpps) {
    const updated = toETDate(item.json._info?.lastUpdated);
    if (updated && inWeek(updated, ws, we)) {
      oppsClosed++;
    }
  }
  oppsClosed += oppsWon; // won is also closed

  wonRevenue = Math.round(wonRevenue * 100) / 100;

  // ---- PROJECTS ----
  let openProjectCount = null, budgetedHours = 0, actualProjectHours = 0;
  if (isCurrentWeek) {
    openProjectCount = openProjects.filter(i => !i.json.closedFlag).length;
    for (const item of openProjects) {
      const p = item.json;
      budgetedHours += parseFloat(p.estimatedHours || p.budgetHours || 0);
      actualProjectHours += parseFloat(p.actualHours || 0);
    }
  }

  rows.push({
    weekStart: ws, opened, closed,
    killRate7, killRate14, slaPct,
    totalHours: Math.round(totalHours * 100) / 100,
    billableHours: Math.round(billableHours * 100) / 100,
    openCount,
    oppsClosed, oppsWon, wonRevenue, openOppsCount, openOppsRevenue,
    openProjectCount, budgetedHours, actualProjectHours
  });
}

// Build SQL - use targeted deletes to preserve snapshot metrics (open_tickets, open_projects)
// Only delete metrics we're about to fully rewrite (all 15 weeks)
const sqlParts = [
  "DELETE FROM scorecard_weekly WHERE section='customer_service' AND metric_name IN ('tickets_opened','tickets_closed','kill_rate_7d','kill_rate_14d','sla_pct_30d','total_hours','billable_hours')",
  "DELETE FROM scorecard_weekly WHERE section='sales' AND metric_name IN ('opps_closed','opps_won','won_revenue','open_opportunities','open_opps_revenue')",
  "DELETE FROM scorecard_weekly WHERE section='projects' AND metric_name IN ('budgeted_hours','actual_project_hours','open_projects')",
  // Clean up old metric names from previous versions (NOT open_tickets — that's snapshot data we preserve)
  "DELETE FROM scorecard_weekly WHERE metric_name IN ('kill_rate','sla_pct','opps_closed_won','sales_revenue')"
];

for (const r of rows) {
  const metrics = [
    ['customer_service', 'tickets_opened', r.opened],
    ['customer_service', 'tickets_closed', r.closed],
    ['customer_service', 'kill_rate_7d', r.killRate7],
    ['customer_service', 'kill_rate_14d', r.killRate14],
    ['customer_service', 'sla_pct_30d', r.slaPct],
    ['customer_service', 'total_hours', r.totalHours],
    ['customer_service', 'billable_hours', r.billableHours],
    ['sales', 'opps_closed', r.oppsClosed],
    ['sales', 'opps_won', r.oppsWon],
    ['sales', 'won_revenue', r.wonRevenue]
  ];

  if (r.openCount !== null) metrics.push(['customer_service', 'open_tickets', r.openCount]);
  metrics.push(['sales', 'open_opportunities', r.openOppsCount]);
  metrics.push(['sales', 'open_opps_revenue', r.openOppsRevenue]);
  if (r.openProjectCount !== null) metrics.push(['projects', 'open_projects', r.openProjectCount]);
  if (r.budgetedHours > 0) metrics.push(['projects', 'budgeted_hours', r.budgetedHours]);
  if (r.actualProjectHours > 0) metrics.push(['projects', 'actual_project_hours', r.actualProjectHours]);

  for (const [section, name, val] of metrics) {
    sqlParts.push(
      "INSERT INTO scorecard_weekly (week_start, section, metric_name, metric_value, updated_at) " +
      "VALUES ('" + r.weekStart + "', '" + section + "', '" + name + "', " + val + ", NOW()) " +
      "ON CONFLICT (week_start, section, metric_name) DO UPDATE SET metric_value = " + val + ", updated_at = NOW()"
    );
  }
}

